+        let mut first_cx = Context::from_waker(&first_waker);
+
+        let second_woken = Arc::new(std::sync::atomic::AtomicBool::new(false));
+        let second_waker = Waker::from(Arc::new(TestWake(Arc::clone(&second_woken))));
